import React, { createContext, useContext, useEffect, useState } from 'react';
import io from 'socket.io-client';
import { useAuth } from './AuthContext';
import { toast } from 'react-toastify';

const SOCKET_URL = process.env.REACT_APP_SOCKET_URL || 'http://localhost:5000';

const SocketContext = createContext();

export const useSocket = () => useContext(SocketContext);

export const SocketProvider = ({ children }) => {
  const [socket, setSocket] = useState(null);
  const [sensorData, setSensorData] = useState(null);
  const [alerts, setAlerts] = useState([]);
  const { isAuthenticated, isAdmin } = useAuth();

  useEffect(() => {
    if (!isAuthenticated) return;

    const newSocket = io(SOCKET_URL);
    setSocket(newSocket);

    newSocket.on('connect', () => {
      console.log('Socket connected');
    });

    newSocket.on('sensor_update', (data) => {
      setSensorData(data);
    });

    newSocket.on('alerts', (newAlerts) => {
      setAlerts((prev) => [...prev, ...newAlerts]);
      
      // Show toast for critical alerts
      newAlerts.forEach(alert => {
        if (alert.type === 'LOW_STOCK') {
          toast.warning(`Low stock: ${alert.container} (${alert.level}kg remaining)`);
        } else if (alert.type === 'LOW_BATTERY') {
          toast.error(`Low battery: ${alert.percentage}%`);
        }
      });
    });

    if (isAdmin) {
      newSocket.on('new_return', (data) => {
        toast.info(`New return request: ${data.return_id}`);
        setAlerts((prev) => [...prev, { type: 'NEW_RETURN', data }]);
      });

      newSocket.on('new_message', (data) => {
        toast.info(`New message from ${data.user_name}`);
      });

      newSocket.on('new_rating', (data) => {
        toast.success(`New ${data.rating}-star rating received`);
      });
    } else {
      newSocket.on('return_processed', (data) => {
        toast.info(`Return ${data.return_id} is now ${data.status}`);
      });

      newSocket.on('message_reply', (data) => {
        toast.info(`You have a reply to your message`);
      });
    }

    return () => {
      newSocket.disconnect();
    };
  }, [isAuthenticated, isAdmin]);

  return (
    <SocketContext.Provider value={{ socket, sensorData, alerts, setAlerts }}>
      {children}
    </SocketContext.Provider>
  );
};
